  postedAt: string
}

export interface ParsedLocation {
  display: string | null      // remote folded in, e.g. "SF / Remote (US)"
  places: string[]
  remoteScope: string | null
}

export interface ParsedApply {
  method: ApplyMethod
  url: string | null          // careers/ATS link, distinct from company homepage
  email: string | null
}
